import React from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Shield, Activity, Users, Globe } from 'lucide-react';

import HumanoidCanvas from '../components/HumanoidCanvas';

const Landing = () => {
    const navigate = useNavigate();

    const handleRoleSelect = (role) => {
        navigate(`/login?role=${role}`);
    };

    return (
        <div className="min-h-screen bg-[#050510] relative text-white selection:bg-cyan-500/30 font-['Outfit'] overflow-x-hidden">
            {/* Cinematic Background */}
            <div className="fixed inset-0 z-0">
                <div className="absolute top-[-10%] left-[-10%] w-[50%] h-[50%] bg-blue-600/10 rounded-full blur-[120px] animate-pulse" />
                <div className="absolute bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-purple-600/10 rounded-full blur-[120px] animate-pulse" />
                <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-[0.03]" />
            </div>

            <div className="relative z-10 max-w-7xl mx-auto px-6 pt-24 pb-12 lg:pt-32">
                <div className="flex flex-col lg:flex-row items-center gap-16 lg:gap-24">

                    {/* Hero Content */}
                    <div className="flex-1 text-center lg:text-left">
                        <motion.div 
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="inline-flex items-center gap-2 bg-white/5 backdrop-blur-xl px-4 py-2 rounded-full border border-white/10 mb-8"
                        >
                            <Activity className="text-cyan-400 w-4 h-4" />
                            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-cyan-400">Industry-Leading 2026 Engine</span>
                        </motion.div>

                        <motion.h1 
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.1 }}
                            className="text-6xl lg:text-8xl font-black tracking-tighter mb-8 uppercase leading-[0.9]"
                        >
                            VITA-CORE <br />
                            <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-cyan-400">2.0</span>
                        </motion.h1>

                        <motion.p 
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            transition={{ delay: 0.2 }}
                            className="text-lg text-white/50 max-w-xl mx-auto lg:mx-0 leading-relaxed mb-12"
                        >
                            The world’s first agentic, HL7 FHIR-compliant disease prediction ecosystem. 
                            Augmenting human clinical decisions with real-time explainable AI reasoning.
                        </motion.p>

                        <div className="flex flex-col sm:flex-row gap-4 justify-center lg:justify-start">
                            <motion.button 
                                whileHover={{ scale: 1.05 }}
                                whileTap={{ scale: 0.95 }}
                                onClick={() => handleRoleSelect('patient')}
                                className="px-10 py-5 bg-gradient-to-r from-blue-600 to-cyan-500 rounded-2xl font-black text-xs uppercase tracking-widest shadow-[0_0_30px_rgba(37,99,235,0.4)] hover:shadow-[0_0_50px_rgba(6,182,212,0.6)] transition-all"
                            >
                                Launch Patient Portal
                            </motion.button>
                            <motion.button 
                                whileHover={{ scale: 1.05 }}
                                whileTap={{ scale: 0.95 }}
                                onClick={() => handleRoleSelect('doctor')}
                                className="px-10 py-5 bg-white/5 backdrop-blur-xl border border-white/10 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-white/10 transition-all"
                            >
                                Clinician Dashboard
                            </motion.button>
                        </div>

                        {/* Standard Badges */}
                        <div className="mt-16 flex flex-wrap justify-center lg:justify-start gap-8 text-white/20">
                            <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.2em]">
                                <Globe className="w-3 h-3 text-cyan-500/50" /> HL7 FHIR GLOBAL
                            </div>
                            <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.2em]">
                                <Shield className="w-3 h-3 text-cyan-500/50" /> HIPAA AES-256
                            </div>
                            <div className="flex items-center gap-2 text-[10px] font-black uppercase tracking-[0.2em]">
                                <Activity className="w-3 h-3 text-cyan-500/50" /> AGENTIC AI
                            </div>
                        </div>
                    </div>

                    {/* 3D Digital Twin Hero Section */}
                    <div className="flex-1 relative w-full h-[500px] lg:h-[700px] group">
                        <div className="absolute inset-0 bg-cyan-500/10 blur-[100px] rounded-full scale-50 group-hover:scale-100 transition-transform duration-1000" />
                        <div className="w-full h-full relative z-10">
                            <HumanoidCanvas onSelectPart={() => {}} />
                        </div>

                        {/* Floating Labels */}
                        <div className="absolute top-1/4 right-[10%] bg-black/60 backdrop-blur-md border border-white/10 p-4 rounded-2xl hidden lg:block">
                            <div className="flex items-center gap-3">
                                <div className="w-2 h-2 bg-cyan-400 rounded-full animate-ping" />
                                <span className="text-[10px] font-bold text-cyan-400 uppercase tracking-widest whitespace-nowrap">Live Neural Mapping</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Landing;
